from flask import Flask, request, jsonify, send_file, abort
import os

app = Flask(__name__)
BASE_DIR = '/path/to/user/root/directory'

def safe_join(base, *paths):
    final_path = os.path.normpath(os.path.join(base, *paths))
    if not final_path.startswith(os.path.normpath(base)):
        raise ValueError("Attempted path traversal detected.")
    return final_path

@app.route('/list', methods=['GET'])
def list_directory():
    user_path = request.args.get('path', '')
    try:
        full_path = safe_join(BASE_DIR, user_path)
        if not os.path.isdir(full_path):
            abort(404)
        files = os.listdir(full_path)
        return jsonify(files)
    except ValueError:
        abort(403)

@app.route('/download', methods=['GET'])
def download_file():
    user_path = request.args.get('path', '')
    try:
        full_path = safe_join(BASE_DIR, user_path)
        if not os.path.isfile(full_path):
            abort(404)
        return send_file(full_path)
    except ValueError:
        abort(403)

@app.route('/info', methods=['GET'])
def get_file_info():
    user_path = request.args.get('path', '')
    try:
        full_path = safe_join(BASE_DIR, user_path)
        if not os.path.exists(full_path):
            abort(404)
        file_info = {
            'size': os.path.getsize(full_path),
            'modified_time': os.path.getmtime(full_path),
            'is_directory': os.path.isdir(full_path)
        }
        return jsonify(file_info)
    except ValueError:
        abort(403)

if __name__ == '__main__':
    app.run(debug=True)